def compile_and_launch_knn_build(*, shape_labels=base_f30c.DISPATCH_CORRECTNESS_SHAPES, benchmark: bool=False) -> dict[str, Any]:
    selected = None if shape_labels is None else _select_contract_shapes(shape_labels)
    report = eval_mod.evaluate(candidate, shapes=selected, correctness=True, benchmark=benchmark)
    passed = bool(report.get('summary', {}).get('all_correct', False))
    report['passed'] = passed
    report['all_pass'] = passed
    return report

def _selected_entrypoint_for_row(row: dict[str, Any]) -> str:
    selected = row.get('selected_entrypoint')
    if selected:
        return str(selected)
    return ROUTE_RESIDUAL_19B3_ENTRYPOINT

def _residual_trace_record(inputs: dict[str, Any]) -> dict[str, Any]:
    label = str(inputs.get('label'))
    base_row = dict(portfolio_19b3.route_trace_for_contract_shapes((label,))[0])
    spec = _RESIDUAL_SHAPE_SPECS[label]
    selected_seed = base_row.get('selected_seed') or SEED_RESIDUAL_19B3_ID
    route_kind = base_row.get('route_kind') or 'general'
    route_source = base_row.get('route_source') or ('shape-specific-seed' if selected_seed != SEED_RESIDUAL_19B3_ID else 'broad-dispatcher')
    if selected_seed == SEED_RESIDUAL_19B3_ID:
        route_source = 'broad-dispatcher'
        route_kind = 'general'
    base_row.update({'shape_key': label, 'selected_entrypoint': _selected_entrypoint_for_row(base_row), 'selected_seed': selected_seed, 'expected_seed': selected_seed, 'route_kind': route_kind, 'route_source': route_source, 'guard_id': '6998_residual_19b3_exact_bucket_guard', 'guard_condition': ''.join(['exact residual BF16 shape label=', format(label, ''), ' B=', format(spec['B'], ''), ' Q=', format(spec['Q'], ''), ' M=', format(spec['M'], ''), ' D=', format(spec['D'], ''), ' K=', format(spec['K'], ''), ' build=', format(spec.get('build', False), '')]), 'wrapper_entrypoint': ROUTE_RESIDUAL_19B3_ENTRYPOINT, 'baseline_dispatcher_route': base_f30c.route_for_contract_inputs(inputs), 'base_f30c_route': base_f30c.route_for_contract_inputs(inputs), 'classification': 'unmeasured'})
    return base_f30c._normalize_route_row(base_row)

def _baseline_trace_record(inputs: dict[str, Any]) -> dict[str, Any]:
    label = str(inputs.get('label'))
    row = dict(base_f30c.route_trace_for_contract_shapes((label,), candidate_key=base_f30c.DEFAULT_CANDIDATE_KEY)[0])
    row['baseline_dispatcher_route'] = row.get('selected_route')
    row['base_f30c_route'] = row.get('selected_route')
    return base_f30c._normalize_route_row(row)

def route_trace_for_contract_shapes(shape_labels=None, *, force_fallback: bool=False, enable_residual_19b3: bool=True) -> list[dict[str, Any]]:
    selected = eval_mod.CANONICAL_SHAPES if shape_labels is None else _select_contract_shapes(shape_labels)
    rows = []
    for shape in selected:
        inputs = base_f30c._trace_inputs_from_shape(shape)
        label = _residual_label_for_inputs(inputs)
        if force_fallback and label is not None:
            row = _baseline_trace_record(inputs)
            row['expected_seed'] = SEED_RESIDUAL_19B3_ID
            row['guard_id'] = 'forced_fallback_6998_residual_19b3_disabled'
            row['guard_condition'] = 'forced fallback to f30c; residual 19b3 overlay disabled'
            row['classification'] = 'guard-miss'
        elif enable_residual_19b3 and label is not None:
            row = _residual_trace_record(inputs)
        else:
            row = _baseline_trace_record(inputs)
        rows.append(base_f30c._normalize_route_row(row))
    return rows

def _rows_for_labels(report: dict[str, Any], labels: tuple[str, ...]) -> dict[str, Any]:
    return base_f30c._rows_for_labels(report, labels)

def _classify_row(row: dict[str, Any], *, speedup_vs_external: float | None, speedup_vs_baseline: float | None) -> str:
    route_kind = row.get('route_kind')
    route_source = row.get('route_source')
    if speedup_vs_external is not None and speedup_vs_external < 1.0:
        return 'kernel-slow' if route_kind == 'specialized' else 'fallback-slow'
    if speedup_vs_external is not None and speedup_vs_external < 1.05:
        return 'kernel-slow' if route_kind == 'specialized' else 'fallback-slow'
    if speedup_vs_baseline is not None and speedup_vs_baseline < 1.0:
        return 'kernel-slow' if route_kind == 'specialized' else 'fallback-slow'
    if route_source == 'shape-specific-seed':
        return 'seed-consumed'
    return 'route-ok'

def _annotate_route_trace(route_trace: list[dict[str, Any]], candidate_report: dict[str, Any], baseline_report: dict[str, Any]) -> list[dict[str, Any]]:
    annotated = []
    for row in route_trace:
        label = str(row.get('shape_key'))
        out = dict(row)
        candidate_row = candidate_report.get('per_shape', {}).get(label, {})
        baseline_row = baseline_report.get('per_shape', {}).get(label, {})
        candidate_ms = candidate_row.get('kernel_ms')
        baseline_ms = baseline_row.get('kernel_ms')
        flashlib_ms = candidate_row.get('flashlib_ms')
        speedup_vs_baseline = baseline_ms / candidate_ms if candidate_ms and baseline_ms else None
        speedup_vs_external = flashlib_ms / candidate_ms if candidate_ms and flashlib_ms else None
        out['dispatcher_kernel_ms'] = candidate_ms
        out['baseline_dispatcher_kernel_ms'] = baseline_ms
        out['external_baseline_ms'] = flashlib_ms
        out['flashlib_ms'] = flashlib_ms
        out['relative_speedup_vs_baseline'] = speedup_vs_baseline
        out['speedup_vs_external_baseline'] = speedup_vs_external
        out['external_baseline_ref'] = 'same_session' if flashlib_ms is not None else 'not_available'
        if label in RESIDUAL_TARGET_SHAPE_SET:
            out['classification'] = _classify_row(out, speedup_vs_external=speedup_vs_external, speedup_vs_baseline=speedup_vs_baseline)
        elif speedup_vs_external is not None and speedup_vs_external < 1.0:
            out['classification'] = 'kernel-slow' if out.get('route_kind') == 'specialized' else 'fallback-slow'
        else:
            out['classification'] = out.get('classification', 'route-ok')
        annotated.append(base_f30c._normalize_route_row(out))
    return annotated

def _seed_delta_matrix(candidate_report: dict[str, Any], baseline_report: dict[str, Any]) -> list[dict[str, Any]]:
    matrix = []
    for label in RESIDUAL_TARGET_SHAPES:
        inputs = base_f30c._inputs_for_label(label)
        candidate_row = candidate_report.get('per_shape', {}).get(label, {})
        baseline_row = baseline_report.get('per_shape', {}).get(label, {})
        candidate_ms = candidate_row.get('kernel_ms')
        baseline_ms = baseline_row.get('kernel_ms')
        matrix.append({'shape_key': label, 'baseline_route': base_f30c.route_for_contract_inputs(inputs), 'candidate_route': route_for_contract_inputs(inputs), 'candidate_id': 'candidate_residual_19b3_overlay_6998_v1', 'candidate_ms': candidate_ms, 'baseline_ms': baseline_ms, 'flashlib_ms': candidate_row.get('flashlib_ms'), 'metric_delta_ms': candidate_ms - baseline_ms if candidate_ms and baseline_ms else None, 'speedup_vs_baseline_dispatcher': baseline_ms / candidate_ms if candidate_ms and baseline_ms else None, 'ratio_vs_flashlib': candidate_row.get('ratio_vs_flashlib'), 'timing_backend': candidate_row.get('timing_backend') or baseline_row.get('timing_backend')})
    return matrix

def benchmark_baseline_f30c(*, use_cupti: bool=True, shape_labels=None, benchmark_correctness: bool=True, time_flashlib: bool=True) -> dict[str, Any]:
    report = _run_with_timing_backend(use_cupti=use_cupti, shape_labels=shape_labels, kernel_fn=candidate_baseline_f30c, correctness=benchmark_correctness, time_flashlib=time_flashlib)
